arguments.argument:
if type=1
{
  if init=0
  {
    effectLimit=0
    init=1
  }
  if global.gamePaused=false
  {
    pDist=point_distance(x,y,oPlayer1.x,oPlayer1.y-22)
    if pDist<384
    {
      if effectLimit<=0
      {
        pX=x-2+random(20)
        pY=y-2+random(36)
        sizeRan=round(random(1))
        effect_create_above(ef_smoke,pX,pY,sizeRan,c_black)
        effectLimit=3
      }
      else
        effectLimit-=1
    }
  }
}

if animPlayerExit>0
{
  animPlayerExit+=1
  oPlayer1.x=x+(sprite_width/2)
  oPlayer1.y+=2
  if animPlayerExit=30
  {
    global.gamePaused=false
    oPlayer1.bCanTakeDamage=true
    oPlayer1.bCanTakeHit=true
    oPlayer1.depth=20
    oPlayer1.x=newX
    oPlayer1.y=newY
    view_xview[0]=newX
    view_yview[0]=newY
    animPlayerExit=0
  }
}
